import React, { useEffect, useMemo, useState } from 'react';
import axios from 'axios';
import { MapPin, Siren } from 'lucide-react';
import { formatTimeAgo } from '../lib/time';

function levelBadge(level) {
  if (level === 'High') return 'bg-red-500/15 text-red-200 ring-1 ring-red-500/25';
  if (level === 'Medium') return 'bg-yellow-400/15 text-yellow-100 ring-1 ring-yellow-400/25';
  return 'bg-emerald-400/15 text-emerald-100 ring-1 ring-emerald-400/25';
}

export default function ReportsPage({ apiBaseUrl, auth, onOpenLive, onGiveReport }) {
  const [reports, setReports] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const axiosClient = useMemo(() => {
    const instance = axios.create({ baseURL: apiBaseUrl });
    if (auth?.token) {
      instance.interceptors.request.use((config) => {
        config.headers = config.headers || {};
        config.headers.Authorization = `Bearer ${auth.token}`;
        return config;
      });
    }
    return instance;
  }, [apiBaseUrl, auth?.token]);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    setError('');
    axiosClient
      .get('/api/reports/active')
      .then((res) => {
        if (!cancelled) setReports(res.data || []);
      })
      .catch((e) => {
        if (!cancelled) setError(e?.response?.data?.msg || 'Failed to load reports');
      })
      .finally(() => {
        if (!cancelled) setLoading(false);
      });

    return () => {
      cancelled = true;
    };
  }, [axiosClient]);

  return (
    <div className="mx-auto w-full max-w-5xl p-4">
      <div className="flex items-center justify-between gap-3">
        <div>
          <div className="text-xl font-bold tracking-tight text-slate-100">Reports</div>
          <div className="mt-1 text-sm text-slate-400">Last 24 hours</div>
        </div>
        <div className="flex flex-wrap gap-2">
          <button
            type="button"
            onClick={() => onGiveReport?.()}
            className="inline-flex items-center gap-2 rounded-2xl bg-white px-4 py-2 text-sm font-semibold text-slate-950 hover:bg-slate-100"
          >
            <Siren size={16} />
            Submit New Report
          </button>
          <button
            type="button"
            onClick={() => onOpenLive?.()}
            className="inline-flex items-center gap-2 rounded-2xl bg-sky-500 px-4 py-2 text-sm font-semibold text-slate-950 hover:bg-sky-400"
          >
            <MapPin size={16} />
            Open Live Map
          </button>
        </div>
      </div>

      <div className="mt-4 rounded-3xl border border-white/10 bg-slate-950/60 p-4 shadow-soft backdrop-blur">
        {loading ? (
          <div className="p-4 text-sm text-slate-300">Loading...</div>
        ) : error ? (
          <div className="p-4 text-sm text-red-200">{error}</div>
        ) : reports.length === 0 ? (
          <div className="p-4 text-sm text-slate-300">No reports yet.</div>
        ) : (
          <div className="grid gap-3">
            {reports.map((r) => {
              const level = r.waterLevel || r.intensity || 'Low';
              const ts = r.createdAt || r.timestamp || r.time;
              const name = r.address || 'Unknown location';
              const coords = r?.location?.coordinates;
              const lng = r.lng ?? (Array.isArray(coords) ? coords[0] : undefined);
              const lat = r.lat ?? (Array.isArray(coords) ? coords[1] : undefined);
              return (
                <div
                  key={r._id || `${lat}-${lng}-${ts}`}
                  className="rounded-2xl border border-white/10 bg-black/20 p-4"
                >
                  <div className="flex flex-wrap items-center justify-between gap-2">
                    <div className="flex items-center gap-2">
                      <span className={`rounded-xl px-2 py-1 text-xs font-semibold ${levelBadge(level)}`}>
                        {level}
                      </span>
                      <span className="text-xs font-semibold text-slate-200">{name}</span>
                      <span className="text-xs text-slate-400">{formatTimeAgo(ts)}</span>
                    </div>
                    <div className="text-xs text-slate-500">
                      {Number.isFinite(lat) && Number.isFinite(lng) ? `(${lat.toFixed(5)}, ${lng.toFixed(5)})` : ''}
                    </div>
                  </div>
                  {r.imageUrl ? (
                    <img
                      src={r.imageUrl}
                      alt="Report"
                      className="mt-3 max-h-56 w-full rounded-2xl object-cover ring-1 ring-white/10"
                    />
                  ) : null}
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}
